template.script:
//
(function() {
  var smTeamsData     = [];
  var smSelectedTeam  = null;
  var smPlayerId      = null;
  var smCountdownTimer = null;

  /* ── Open / Close ──────────────────────────────────────────── */
  window.openSellModal = function() {
    smPlayerId     = parseInt(document.body.getAttribute('data-player-id'));
    smSelectedTeam = null;
    smTeamsData    = [];
    if (smCountdownTimer) { clearInterval(smCountdownTimer); smCountdownTimer = null; }

    // Show form, hide sold screen
    document.getElementById('smFormPanel').style.display = 'block';
    document.getElementById('smSoldScreen').classList.remove('visible');

    // Reset form
    document.getElementById('smTeamBadges').innerHTML = '<span class="sm-no-teams">Loading teams\u2026</span>';
    document.getElementById('smTeamPlaceholder').style.display = 'flex';
    document.getElementById('smTeamLogo').style.display = 'none';
    document.getElementById('smTeamNameLabel').style.display = 'none';
    document.getElementById('teamDetailsStrip').style.display = 'none';
    document.getElementById('sellSuggestion').style.display = 'none';
    document.getElementById('sellError').style.display = 'none';
    document.getElementById('smBtnSell').disabled = true;
    document.getElementById('smBtnSell').textContent = 'Sell Player';
    document.getElementById('sellPoints').value = 0;
    document.getElementById('sellModal').classList.add('open');
    smLoadTeams(smPlayerId);
  };

  window.closeSellModal = function() {
    if (smCountdownTimer) { clearInterval(smCountdownTimer); smCountdownTimer = null; }
    document.getElementById('sellModal').classList.remove('open');
  };

  window.smSkipToNext = function() {
    if (smCountdownTimer) { clearInterval(smCountdownTimer); smCountdownTimer = null; }
    window.location.reload();
  };

  /* ── Load teams ─────────────────────────────────────────────── */
  function smLoadTeams(playerId) {
    fetch('/web/dataset/call_kw', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({
        jsonrpc: '2.0', method: 'call',
        params: { model: 'auction.team.player', method: 'get_sell_teams_data', args: [playerId], kwargs: {} }
      })
    })
    .then(function(r) { return r.json(); })
    .then(function(data) {
      if (data.error) { smShowError('Failed to load teams. Please try again.'); return; }
      smTeamsData = data.result || [];
      smRenderBadges(smTeamsData);
    })
    .catch(function() { smShowError('Network error loading teams.'); });
  }

  function smRenderBadges(teams) {
    var container = document.getElementById('smTeamBadges');
    if (!teams.length) {
      container.innerHTML = '<span class="sm-no-teams">No teams available</span>';
      return;
    }
    container.innerHTML = '';
    teams.forEach(function(team) {
      var btn = document.createElement('button');
      var disabled = !team.tier_slots_ok || !team.budget_ok;
      btn.className = 'sm-badge' + (disabled ? ' tier-full' : '');
      btn.textContent = team.team_name;
      btn.dataset.teamId = team.team_id;
      if (!team.tier_slots_ok) {
        btn.title = 'Tier slot full for this team';
        btn.disabled = true;
      } else if (!team.budget_ok) {
        btn.title = 'Insufficient budget \u2014 cannot meet this tier\u2019s minimum bid';
        btn.disabled = true;
      } else {
        btn.onclick = function() { smSelectTeam(team); };
      }
      container.appendChild(btn);
    });
  }

  /* ── Select team ─────────────────────────────────────────────── */
  function smSelectTeam(team) {
    smSelectedTeam = team;
    document.querySelectorAll('.sm-badge').forEach(function(b) {
      b.classList.toggle('active', b.dataset.teamId == team.team_id);
    });
    var logo = document.getElementById('smTeamLogo');
    logo.src = '/web/image/auction.team/' + team.team_id + '/logo';
    logo.style.display = 'block';
    document.getElementById('smTeamPlaceholder').style.display = 'none';
    var lbl = document.getElementById('smTeamNameLabel');
    lbl.textContent = team.team_name; lbl.style.display = 'block';

    document.getElementById('smRemainingPts').textContent     = team.remaining_points;
    document.getElementById('smRemainingPlayers').textContent = team.remaining_players;
    document.getElementById('smMaxCall').textContent          = team.max_call;
    document.getElementById('teamDetailsStrip').style.display = 'flex';

    var sug = document.getElementById('sellSuggestion');
    sug.innerHTML = team.remaining_players > 1
      ? '\u2139 Max bid <strong>' + team.max_call + ' pts</strong> &#160;|&#160; Base for remaining: <strong>' + team.effective_base_point + ' pts</strong>'
      : '\u2139 Last player slot! Max bid: <strong>' + team.max_call + ' pts</strong>';
    sug.style.display = 'block';

    var input = document.getElementById('sellPoints');
    input.value = team.effective_base_point;
    input.min   = team.effective_base_point;
    input.max   = team.max_call;
    document.getElementById('smBtnSell').disabled = false;
    smHideError();
  }

  /* ── Adjust points ───────────────────────────────────────────── */
  window.smAdjustPoints = function(dir) {
    if (!smSelectedTeam) return;
    var input   = document.getElementById('sellPoints');
    var current = parseInt(input.value) || smSelectedTeam.effective_base_point;
    var inc     = smGetIncrement(current, smSelectedTeam.slabs);
    var next    = Math.min(Math.max(current + dir * inc, smSelectedTeam.effective_base_point), smSelectedTeam.max_call);
    input.value = next;
    smHideError();
  };

  function smGetIncrement(amount, slabs) {
    if (!slabs || !slabs.length) return 50;
    for (var i = 0; i < slabs.length; i++) {
      var s = slabs[i];
      if (amount >= s.from_amount && amount <= s.to_amount) return s.increment;
    }
    return slabs[slabs.length - 1].increment || 50;
  }

  /* ── Submit sell ─────────────────────────────────────────────── */
  window.smSubmitSell = function() {
    if (!smSelectedTeam || !smPlayerId) return;
    var finalPoint = parseInt(document.getElementById('sellPoints').value);
    if (isNaN(finalPoint) || finalPoint <= 0) { smShowError('Please enter a valid points value.'); return; }

    var btn = document.getElementById('smBtnSell');
    btn.disabled = true; btn.textContent = 'Selling\u2026';
    smHideError();

    fetch('/web/dataset/call_kw', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({
        jsonrpc: '2.0', method: 'call',
        params: {
          model: 'auction.team.player', method: 'action_sell_from_web',
          args: [smPlayerId, smSelectedTeam.team_id, finalPoint], kwargs: {}
        }
      })
    })
    .then(function(r) { return r.json(); })
    .then(function(data) {
      if (data.error) {
        var msg = data.error.data ? data.error.data.message : data.error.message;
        smShowError('Error: ' + msg);
        btn.disabled = false; btn.textContent = 'Sell Player'; return;
      }
      var result = data.result;
      if (!result.success) {
        smShowError(result.error);
        btn.disabled = false; btn.textContent = 'Sell Player'; return;
      }
      smShowSoldScreen(result);
    })
    .catch(function() {
      smShowError('Network error. Please try again.');
      btn.disabled = false; btn.textContent = 'Sell Player';
    });
  };

  /* ── Sold celebration screen ─────────────────────────────────── */
  function smShowSoldScreen(result) {
    // Hide form, show sold screen
    document.getElementById('smFormPanel').style.display = 'none';
    var soldScreen = document.getElementById('smSoldScreen');

    // Fill in data
    document.getElementById('smSoldPhoto').src     = '/web/image/auction.team.player/' + result.player_id + '/photo';
    document.getElementById('smSoldTeamLogo').src  = '/web/image/auction.team/' + result.team_id + '/logo';
    document.getElementById('smSoldTeamName').textContent = result.team_name;
    document.getElementById('smSoldPoints').textContent   = result.final_point;

    // Re-trigger stamp animation by cloning the stamp element
    var oldStamp = document.querySelector('.sm-sold-stamp');
    var newStamp = oldStamp.cloneNode(true);
    oldStamp.parentNode.replaceChild(newStamp, oldStamp);

    soldScreen.classList.add('visible');

    // Countdown
    var totalSecs = (result.display_seconds && result.display_seconds > 0) ? result.display_seconds : 5;
    var remaining = totalSecs;
    var bar = document.getElementById('smProgressBar');
    bar.style.transition = 'none';
    bar.style.width = '100%';
    document.getElementById('smCountdownNum').textContent = remaining;

    // Force reflow then start shrinking
    bar.offsetWidth;
    bar.style.transition = 'width ' + totalSecs + 's linear';
    bar.style.width = '0%';

    smCountdownTimer = setInterval(function() {
      remaining -= 1;
      document.getElementById('smCountdownNum').textContent = remaining;
      if (remaining <= 0) {
        clearInterval(smCountdownTimer);
        smCountdownTimer = null;
        window.location.reload();
      }
    }, 1000);
  }

  function smShowError(msg) { var el = document.getElementById('sellError'); el.textContent = msg; el.style.display = 'block'; }
  function smHideError()    { document.getElementById('sellError').style.display = 'none'; }

  // Close on overlay click (only on form panel, not during sold screen)
  document.getElementById('sellModal').addEventListener('click', function(e) {
    if (e.target === this && document.getElementById('smFormPanel').style.display !== 'none') closeSellModal();
  });
})();
//
